import{c as t,Q as a,j as o,m as s}from"./chunks/framework.BBA2dIOt.js";const m=JSON.parse('{"title":"Email newsletter inbox","description":"","frontmatter":{},"headers":[],"relativePath":"email-inbox.md","filePath":"email-inbox.md","lastUpdated":1780934257000}'),n={name:"email-inbox.md"};function r(i,e,d,l,c,h){return a(),o("div",null,[...e[0]||(e[0]=[s(`<h1 id="email-newsletter-inbox" tabindex="-1">Email newsletter inbox <a class="header-anchor" href="#email-newsletter-inbox" aria-label="Permalink to &quot;Email newsletter inbox&quot;">​</a></h1><p>Each Ember user gets a unique address (e.g. <code>01234ABCDEFG@mail.example.com</code>). Mail sent there lands in a per-user &quot;Newsletters&quot; feed, alongside RSS articles. Substack, Beehiiv, mailchimp lists — anything you&#39;d otherwise read in email — go through the same reader UI, the same filters, the same digest.</p><p>The feature is <strong>off by default</strong>. Setting <code>EMBER_EMAIL_DOMAIN</code> turns it on.</p><h2 id="what-the-operator-has-to-do" tabindex="-1">What the operator has to do <a class="header-anchor" href="#what-the-operator-has-to-do" aria-label="Permalink to &quot;What the operator has to do&quot;">​</a></h2><p>You&#39;re terminating inbound SMTP for a domain. That requires:</p><ol><li><strong>A domain you control with an MX record pointing at the Ember host.</strong> A subdomain like <code>mail.example.com</code> is fine — keep your main MX for human mail.</li><li><strong>Inbound port 25 reachable</strong>, OR a fronting relay (Caddy layer4, haproxy, nginx stream, postfix) forwarding to Ember&#39;s listener port.</li><li><strong>Set <code>EMBER_EMAIL_DOMAIN</code></strong> to the domain in the address (e.g. <code>mail.example.com</code>). Without it, the SMTP listener doesn&#39;t start and the inbox endpoints return <code>enabled: false</code>.</li></ol><h3 id="recommended-setup-caddy-layer4-→-ember" tabindex="-1">Recommended setup: Caddy layer4 → Ember <a class="header-anchor" href="#recommended-setup-caddy-layer4-→-ember" aria-label="Permalink to &quot;Recommended setup: Caddy layer4 → Ember&quot;">​</a></h3><p>Ember&#39;s listener binds <code>:2525</code> by default (privileged port 25 requires root or <code>CAP_NET_BIND_SERVICE</code>). Front it with Caddy so port 25 stays reverse- proxied:</p><div class="language-caddy vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">caddy</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>{</span></span>
<span class="line"><span>  layer4 {</span></span>
<span class="line"><span>    :25 {</span></span>
<span class="line"><span>      route {</span></span>
<span class="line"><span>        proxy ember:2525</span></span>
<span class="line"><span>      }</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span>  }</span></span>
<span class="line"><span>}</span></span></code></pre></div><p>If you prefer postfix / native :25 binding, change <code>EMBER_EMAIL_LISTEN_ADDR</code> to <code>:25</code> and run Ember with the capability.</p><h2 id="env-vars" tabindex="-1">Env vars <a class="header-anchor" href="#env-vars" aria-label="Permalink to &quot;Env vars&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Variable</th><th>Default</th><th>Notes</th></tr></thead><tbody><tr><td><code>EMBER_EMAIL_DOMAIN</code></td><td>(unset)</td><td>Required to enable. The host part of generated addresses.</td></tr><tr><td><code>EMBER_EMAIL_LISTEN_ADDR</code></td><td><code>:2525</code></td><td>SMTP bind address.</td></tr><tr><td><code>EMBER_EMAIL_MAX_BYTES</code></td><td><code>26214400</code> (25 MiB)</td><td>Per-message size cap.</td></tr></tbody></table><h2 id="security" tabindex="-1">Security <a class="header-anchor" href="#security" aria-label="Permalink to &quot;Security&quot;">​</a></h2><ul><li><strong>Open-relay protection.</strong> The listener accepts mail only when the envelope <code>RCPT TO</code> exactly matches an active <code>&lt;handle&gt;@&lt;EMBER_EMAIL_DOMAIN&gt;</code>. Every other recipient is rejected with <code>550 5.1.1 no such mailbox</code>.</li><li><strong>No AUTH required, no AUTH accepted.</strong> This is an inbound-only MX, not a submission service.</li><li><strong>No SPF / DKIM verification today.</strong> The handle itself is the auth token (~60 bits of entropy); spoofing requires guessing it. Verifying SPF / DKIM is a planned follow-up — for now operators worried about spoofed senders should front Ember with a real MTA (postfix + opendkim + spamassassin) that does the verification and forwards the clean messages over LMTP.</li><li><strong>Body size capped</strong> at <code>EMBER_EMAIL_MAX_BYTES</code>. Attachments are read but not extracted.</li></ul><h2 id="address-rotation" tabindex="-1">Address rotation <a class="header-anchor" href="#address-rotation" aria-label="Permalink to &quot;Address rotation&quot;">​</a></h2><p>If a handle gets sold or leaks, hit the <strong>Rotate address</strong> button in Settings → Email inbox. A new handle takes effect immediately; the old one keeps accepting mail for <strong>7 days</strong> so existing newsletter subscriptions can be updated without losing in-flight issues.</p><h2 id="what-gets-stored" tabindex="-1">What gets stored <a class="header-anchor" href="#what-gets-stored" aria-label="Permalink to &quot;What gets stored&quot;">​</a></h2><p>Each incoming message becomes one article row. The article uses:</p><ul><li><strong>Title:</strong> the <code>Subject:</code> header (or &quot;(no subject)&quot;).</li><li><strong>Author:</strong> the <code>From:</code> display name, falling back to the address.</li><li><strong>Body:</strong> <code>text/html</code> part if present; falls back to <code>text/plain</code>. HTML is also converted to plain text for full-text search.</li><li><strong>Published at:</strong> the <code>Date:</code> header.</li></ul><p>The synthetic feed has <code>kind=&#39;email&#39;</code> so the RSS poller skips it. The article participates in all the existing flows — read state, summaries (if Ollama is enabled), filters (you can auto-tag newsletters, route them to a board, etc.), search, digest emails.</p>`,20)])])}const u=t(n,[["render",r]]);export{m as __pageData,u as default};
